namespace sv_1f2f38347edb496181b1d3ce161015ac.Services;

public record TaskItem(int Id, string Title, string Assignee, string Priority, DateTime DueDate, string Status);

public interface ITaskService
{
    Task<List<TaskItem>> GetAllTasksAsync();
    Task<TaskItem> CreateTaskAsync(string title, string assignee, string priority, DateTime dueDate);
    Task UpdateTaskStatusAsync(int taskId, string newStatus);
}

@page "/board"
@using sv_1f2f38347edb496181b1d3ce161015ac.Services
@inject ITaskService TaskService
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h1>Project Board</h1>

@if (_loading)
{
    <div class="board-loading">
        <p>Loading tasks…</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="board-error">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-secondary btn-sm" @onclick="LoadTasksAsync">Retry</button>
    </div>
}
else
{
    <!-- Stats bar -->
    <div class="stats-bar">
        <span class="stat-item">Total: <strong>@FilteredTasks.Count</strong></span>
        <span class="stat-item">To&nbsp;Do: <strong>@TasksInColumn("To Do").Count</strong></span>
        <span class="stat-item">In&nbsp;Progress: <strong>@TasksInColumn("In Progress").Count</strong></span>
        <span class="stat-item">Done: <strong>@TasksInColumn("Done").Count</strong></span>
        <span class="stat-item stat-overdue">Overdue: <strong>@OverdueCount</strong></span>
    </div>

    <!-- Search -->
    <div class="search-bar">
        <input type="text" class="form-control" placeholder="Search tasks by title…"
               @bind="_searchTerm" @bind:event="oninput" />
    </div>

    <!-- Columns -->
    <div class="board-columns">
        @foreach (var column in Columns)
        {
            var columnTasks = TasksInColumn(column);
            var columnIndex = Array.IndexOf(Columns, column);

            <div class="board-column">
                <div class="column-header">
                    <h5>@column</h5>
                    <span class="badge bg-secondary">@columnTasks.Count</span>
                </div>

                <div class="column-body">
                    @foreach (var task in columnTasks)
                    {
                        <div class="task-card">
                            <div class="task-title">@task.Title</div>
                            <div class="task-assignee">@task.Assignee</div>
                            <span class="badge priority-badge @PriorityClass(task.Priority)">@task.Priority</span>
                            <div class="task-due">@task.DueDate.ToString("MMM dd")</div>
                            <div class="task-actions">
                                @if (columnIndex > 0)
                                {
                                    var leftStatus = Columns[columnIndex - 1];
                                    <button class="btn btn-sm btn-outline-secondary"
                                            @onclick="() => MoveTaskAsync(task.Id, leftStatus)">← Move Left</button>
                                }
                                @if (columnIndex < Columns.Length - 1)
                                {
                                    var rightStatus = Columns[columnIndex + 1];
                                    <button class="btn btn-sm btn-outline-secondary"
                                            @onclick="() => MoveTaskAsync(task.Id, rightStatus)">Move Right →</button>
                                }
                            </div>
                        </div>
                    }
                </div>

                @if (_addingToColumn == column)
                {
                    <div class="add-task-form">
                        <input type="text" class="form-control form-control-sm mb-1" placeholder="Title"
                               @bind="_newTitle" />
                        <input type="text" class="form-control form-control-sm mb-1" placeholder="Assignee"
                               @bind="_newAssignee" />
                        <select class="form-select form-select-sm mb-1" @bind="_newPriority">
                            <option value="High">High</option>
                            <option value="Medium">Medium</option>
                            <option value="Low">Low</option>
                        </select>
                        <input type="date" class="form-control form-control-sm mb-1"
                               @bind="_newDueDate" />
                        <div class="d-flex gap-1">
                            <button class="btn btn-sm btn-primary" @onclick="() => SaveNewTaskAsync(column)">Save</button>
                            <button class="btn btn-sm btn-outline-secondary" @onclick="CancelAdd">Cancel</button>
                        </div>
                    </div>
                }
                else
                {
                    <button class="btn btn-sm btn-outline-primary add-task-btn" @onclick="() => BeginAdd(column)">
                        + Add Task
                    </button>
                }
            </div>
        }
    </div>
}

@code {
    private static readonly string[] Columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> _allTasks = [];
    private bool _loading = true;
    private string? _errorMessage;
    private string _searchTerm = string.Empty;

    // Add-task form state
    private string? _addingToColumn;
    private string _newTitle = string.Empty;
    private string _newAssignee = string.Empty;
    private string _newPriority = "Medium";
    private DateTime _newDueDate = DateTime.Today.AddDays(7);

    private List<TaskItem> FilteredTasks =>
        string.IsNullOrWhiteSpace(_searchTerm)
            ? _allTasks
            : _allTasks.Where(t => t.Title.Contains(_searchTerm, StringComparison.OrdinalIgnoreCase)).ToList();

    private List<TaskItem> TasksInColumn(string status) =>
        FilteredTasks.Where(t => t.Status == status).ToList();

    private int OverdueCount =>
        FilteredTasks.Count(t => t.DueDate < DateTime.Today && t.Status != "Done");

    protected override async Task OnInitializedAsync() => await LoadTasksAsync();

    private async Task LoadTasksAsync()
    {
        _loading = true;
        _errorMessage = null;

        try
        {
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var idx = _allTasks.FindIndex(t => t.Id == taskId);
            if (idx >= 0)
            {
                _allTasks[idx] = _allTasks[idx] with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private void BeginAdd(string column)
    {
        _addingToColumn = column;
        _newTitle = string.Empty;
        _newAssignee = string.Empty;
        _newPriority = "Medium";
        _newDueDate = DateTime.Today.AddDays(7);
    }

    private void CancelAdd() => _addingToColumn = null;

    private async Task SaveNewTaskAsync(string column)
    {
        if (string.IsNullOrWhiteSpace(_newTitle))
            return;

        try
        {
            var created = await TaskService.CreateTaskAsync(_newTitle, _newAssignee, _newPriority, _newDueDate);
            // The service creates tasks; ensure it lands in the right column
            _allTasks.Add(created.Status == column ? created : created with { Status = column });
            _addingToColumn = null;
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to create task: {ex.Message}";
        }
    }

    private static string PriorityClass(string priority) => priority switch
    {
        "High" => "priority-high",
        "Medium" => "priority-medium",
        "Low" => "priority-low",
        _ => ""
    };
}

.stats-bar {
    display: flex;
    gap: 1.25rem;
    flex-wrap: wrap;
    padding: 0.75rem 1rem;
    margin-bottom: 0.75rem;
    background: #f8f9fa;
    border-radius: 0.375rem;
}

.stat-item {
    font-size: 0.9rem;
}

.stat-overdue strong {
    color: #dc3545;
}

.search-bar {
    max-width: 400px;
    margin-bottom: 1rem;
}

.board-columns {
    display: flex;
    gap: 1rem;
    align-items: flex-start;
}

.board-column {
    flex: 1;
    min-width: 0;
    background: #f0f0f0;
    border-radius: 0.5rem;
    padding: 0.75rem;
    display: flex;
    flex-direction: column;
}

.column-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.5rem;
}

.column-header h5 {
    margin: 0;
}

.column-body {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    min-height: 60px;
}

.task-card {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
    padding: 0.75rem;
}

.task-title {
    font-weight: 600;
    margin-bottom: 0.25rem;
}

.task-assignee {
    font-size: 0.85rem;
    color: #6c757d;
    margin-bottom: 0.25rem;
}

.task-due {
    font-size: 0.8rem;
    color: #495057;
    margin-top: 0.25rem;
}

.task-actions {
    display: flex;
    gap: 0.25rem;
    margin-top: 0.5rem;
}

.priority-badge {
    font-size: 0.75rem;
}

::deep .priority-high {
    background-color: #dc3545 !important;
    color: #fff;
}

::deep .priority-medium {
    background-color: #ffc107 !important;
    color: #212529;
}

::deep .priority-low {
    background-color: #198754 !important;
    color: #fff;
}

.add-task-form {
    margin-top: 0.5rem;
    padding: 0.75rem;
    background: #fff;
    border: 1px dashed #adb5bd;
    border-radius: 0.375rem;
}

.add-task-btn {
    margin-top: 0.5rem;
    width: 100%;
}

.board-loading,
.board-error {
    text-align: center;
    padding: 3rem 1rem;
}

.board-error {
    color: #dc3545;
}

namespace sv_1f2f38347edb496181b1d3ce161015ac.Services;

public record TaskItem(int Id, string Title, string Assignee, string Priority, DateTime DueDate, string Status);

public interface ITaskService
{
    Task<List<TaskItem>> GetAllTasksAsync();
    Task<TaskItem> CreateTaskAsync(string title, string assignee, string priority, DateTime dueDate);
    Task UpdateTaskStatusAsync(int taskId, string newStatus);
}

