@code {
    private static readonly string[] Columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> _allTasks = [];
    private bool _loading = true;
    private string? _errorMessage;
    private string _searchTerm = string.Empty;

    // Add-task form state
    private string? _addingToColumn;
    private string _newTitle = string.Empty;
    private string _newAssignee = string.Empty;
    private string _newPriority = "Medium";
    private DateTime _newDueDate = DateTime.Today.AddDays(7);

    private List<TaskItem> FilteredTasks =>
        string.IsNullOrWhiteSpace(_searchTerm)
            ? _allTasks
            : _allTasks.Where(t => t.Title.Contains(_searchTerm, StringComparison.OrdinalIgnoreCase)).ToList();

    private List<TaskItem> TasksInColumn(string status) =>
        FilteredTasks.Where(t => t.Status == status).ToList();

    private int OverdueCount =>
        FilteredTasks.Count(t => t.DueDate < DateTime.Today && t.Status != "Done");

    protected override async Task OnInitializedAsync() => await LoadTasksAsync();

    private async Task LoadTasksAsync()
    {
        _loading = true;
        _errorMessage = null;

        try
        {
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var idx = _allTasks.FindIndex(t => t.Id == taskId);
            if (idx >= 0)
            {
                _allTasks[idx] = _allTasks[idx] with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private void BeginAdd(string column)
    {
        _addingToColumn = column;
        _newTitle = string.Empty;
        _newAssignee = string.Empty;
        _newPriority = "Medium";
        _newDueDate = DateTime.Today.AddDays(7);
    }

    private void CancelAdd() => _addingToColumn = null;

    private async Task SaveNewTaskAsync(string column)
    {
        if (string.IsNullOrWhiteSpace(_newTitle))
            return;

        try
        {
            var created = await TaskService.CreateTaskAsync(_newTitle, _newAssignee, _newPriority, _newDueDate);
            // The service creates tasks; ensure it lands in the right column
            _allTasks.Add(created.Status == column ? created : created with { Status = column });
            _addingToColumn = null;
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to create task: {ex.Message}";
        }
    }

    private static string PriorityClass(string priority) => priority switch
    {
        "High" => "priority-high",
        "Medium" => "priority-medium",
        "Low" => "priority-low",
        _ => ""
    };
}
"}

