.stats-bar {
    display: flex;
    gap: 1.25rem;
    flex-wrap: wrap;
    padding: 0.75rem 1rem;
    margin-bottom: 0.75rem;
    background: #f8f9fa;
    border-radius: 0.375rem;
}

.stat-item {
    font-size: 0.9rem;
}

.stat-overdue strong {
    color: #dc3545;
}

.search-bar {
    max-width: 400px;
    margin-bottom: 1rem;
}

.board-columns {
    display: flex;
    gap: 1rem;
    align-items: flex-start;
}

.board-column {
    flex: 1;
    min-width: 0;
    background: #f0f0f0;
    border-radius: 0.5rem;
    padding: 0.75rem;
    display: flex;
    flex-direction: column;
}

.column-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.5rem;
}

.column-header h5 {
    margin: 0;
}

.column-body {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    min-height: 60px;
}

.task-card {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
    padding: 0.75rem;
}

.task-title {
    font-weight: 600;
    margin-bottom: 0.25rem;
}

.task-assignee {
    font-size: 0.85rem;
    color: #6c757d;
    margin-bottom: 0.25rem;
}

.task-due {
    font-size: 0.8rem;
    color: #495057;
    margin-top: 0.25rem;
}

.task-actions {
    display: flex;
    gap: 0.25rem;
    margin-top: 0.5rem;
}

.priority-badge {
    font-size: 0.75rem;
}

::deep .priority-high {
    background-color: #dc3545 !important;
    color: #fff;
}

::deep .priority-medium {
    background-color: #ffc107 !important;
    color: #212529;
}

::deep .priority-low {
    background-color: #198754 !important;
    color: #fff;
}

.add-task-form {
    margin-top: 0.5rem;
    padding: 0.75rem;
    background: #fff;
    border: 1px dashed #adb5bd;
    border-radius: 0.375rem;
}

.add-task-btn {
    margin-top: 0.5rem;
    width: 100%;
}

.board-loading,
.board-error {
    text-align: center;
    padding: 3rem 1rem;
}

.board-error {
    color: #dc3545;
}

